    МассивСчетов = Новый Массив;
    Пока ВыборкаИерархия.Следующий() Цикл
        МассивСчетов.Добавить(ВыборкаИерархия.Ссылка);
    КонецЦикла;
    Если МассивСчетов.Количество() = 0 Тогда
        Возврат 0;
    КонецЕсли;

    // Дебет
    ЗапросДт = Новый Запрос;
    ЗапросДт.Текст = 
    "ВЫБРАТЬ
        СУММА(Хозрасчетный.Сумма) КАК СуммаДт
    ИЗ
        РегистрБухгалтерии.Хозрасчетный КАК Хозрасчетный
    ГДЕ
        Хозрасчетный.СчетДт В(&Счета)";
    ЗапросДт.УстановитьПараметр("Счета", МассивСчетов);
    РезультатДт = ЗапросДт.Выполнить();
    ВыборкаДт = РезультатДт.Выбрать();
    Если ВыборкаДт.Следующий() Тогда
        СуммаДт = ВыборкаДт.СуммаДт;
    Иначе
        СуммаДт = 0;
    КонецЕсли;

    // Кредит
    ЗапросКт = Новый Запрос;
    ЗапросКт.Текст = 
    "ВЫБРАТЬ
        СУММА(Хозрасчетный.Сумма) КАК СуммаКт
    ИЗ
        РегистрБухгалтерии.Хозрасчетный КАК Хозрасчетный
    ГДЕ
        Хозрасчетный.СчетКт В(&Счета)";
    ЗапросКт.УстановитьПараметр("Счета", МассивСчетов);
    РезультатКт = ЗапросКт.Выполнить();
    ВыборкаКт = РезультатКт.Выбрать();
    Если ВыборкаКт.Следующий() Тогда
        СуммаКт = ВыборкаКт.СуммаКт;
    Иначе
        СуммаКт = 0;
    КонецЕсли;

    СуммаДт = Если Не ЗначениеЗаполнено(СуммаДт) Тогда 0 Иначе СуммаДт;
    СуммаКт = Если Не ЗначениеЗаполнено(СуммаКт) Тогда 0 Иначе СуммаКт;

    Если Счет.Вид = ВидСчета.Пассивный Тогда
        Сальдо = СуммаКт - СуммаДт;
    Иначе
        Сальдо = СуммаДт - СуммаКт;
    КонецЕсли;

    Возврат Сальдо;
КонецФункции
